1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
16	
17	const sumBasePremiums = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
19	
20	const computePremium = (items: Item[]): number => {
21	  const base = sumBasePremiums(items);
22	  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
23	  return withFirstInsurance + PROCESSING_FEE;
24	};
25	
26	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
27	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
28	const roundUpToGold = (amount: number): number =>
29	  Math.ceil(Math.round(amount * 1e6) / 1e6);
30	
31	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
32	  const results = scenario.steps.map((step) => ({
33	    premium: roundUpToGold(computePremium(step.items)),
34	  }));
35	  return { results };
36	};
